import { describe, it, expect } from 'vitest';
import { forkRaceFold, forkFold, type ForkTask } from '../src/frf';
import { Verdict, isAccept, isDefer, isReject } from '@a0n/bitwise/triton-verdict';

const sum = (xs: ReadonlyArray<number>): number =>
  xs.reduce((a, b) => a + b, 0);

const delay = (ms: number): Promise<void> =>
  new Promise((resolve) => setTimeout(resolve, ms));

describe('forkRaceFold', () => {
  it('3 forks, no race, identity fold (sum)', async () => {
    const forks: ForkTask<number>[] = [
      async () => 1,
      async () => 2,
      async () => 3,
    ];
    const { output, report } = await forkRaceFold({ forks, fold: sum });
    expect(output).toBe(6);
    expect(report).toEqual({
      forkCount: 3,
      fulfilledCount: 3,
      rejectedCount: 0,
      survivorCount: 3,
    });
  });

  it('empty forks throws RangeError', async () => {
    await expect(
      forkRaceFold({ forks: [], fold: (x) => x.length }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('all-rejected throws specific error', async () => {
    const forks: ForkTask<number>[] = [
      async () => {
        throw new Error('a');
      },
      async () => {
        throw new Error('b');
      },
      async () => {
        throw new Error('c');
      },
    ];
    await expect(forkRaceFold({ forks, fold: sum })).rejects.toThrow(
      /all forks rejected/,
    );
  });

  it('race filters out odd numbers', async () => {
    const forks: ForkTask<number>[] = [1, 2, 3, 4, 5].map(
      (v) => async () => v,
    );
    const { output, report } = await forkRaceFold({
      forks,
      race: (arr) => arr.filter((x) => x % 2 === 0),
      fold: sum,
    });
    expect(output).toBe(6); // 2 + 4
    expect(report.survivorCount).toBe(2);
    expect(report.fulfilledCount).toBe(5);
    expect(report.rejectedCount).toBe(0);
  });

  it('empty after race throws specific error', async () => {
    const forks: ForkTask<number>[] = [1, 3, 5].map(
      (v) => async () => v,
    );
    await expect(
      forkRaceFold({
        forks,
        race: (arr) => arr.filter((x) => x % 2 === 0),
        fold: sum,
      }),
    ).rejects.toThrow(/no survivors after race/);
  });

  it('abortOnReject re-throws first rejection', async () => {
    const forks: ForkTask<number>[] = [
      async () => 1,
      async () => {
        throw new Error('boom');
      },
      async () => 3,
    ];
    await expect(
      forkRaceFold({ forks, fold: sum, abortOnReject: true }),
    ).rejects.toThrow(/boom/);

    // Without abortOnReject, the rejection is dropped and fold sees survivors.
    const { output, report } = await forkRaceFold({ forks, fold: sum });
    expect(output).toBe(4); // 1 + 3
    expect(report.fulfilledCount).toBe(2);
    expect(report.rejectedCount).toBe(1);
    expect(report.survivorCount).toBe(2);
  });

  it('determinism: fold receives results in fork-input order, not completion order', async () => {
    // Resolve in REVERSE order: index 0 has the longest delay.
    const forks: ForkTask<number>[] = [
      async () => {
        await delay(30);
        return 10;
      },
      async () => {
        await delay(20);
        return 20;
      },
      async () => {
        await delay(10);
        return 30;
      },
    ];
    const { output } = await forkRaceFold<number, number[]>({
      forks,
      fold: (arr) => Array.from(arr),
    });
    expect(output).toEqual([10, 20, 30]);
  });

  it('concurrency cap limits in-flight forks', async () => {
    let inFlight = 0;
    let maxObserved = 0;

    const makeTask = (): ForkTask<number> => async () => {
      inFlight++;
      if (inFlight > maxObserved) maxObserved = inFlight;
      await delay(15);
      const observed = inFlight;
      inFlight--;
      return observed;
    };

    const forks: ForkTask<number>[] = [
      makeTask(),
      makeTask(),
      makeTask(),
      makeTask(),
      makeTask(),
    ];

    const { output, report } = await forkRaceFold<number, number>({
      forks,
      fold: (arr) => Math.max(...arr),
      concurrency: 2,
    });
    expect(maxObserved).toBeLessThanOrEqual(2);
    expect(output).toBeLessThanOrEqual(2);
    expect(report.forkCount).toBe(5);
    expect(report.fulfilledCount).toBe(5);
  });

  it('TritonVerdict: clean run Accepts, partial run Abstains (defer), all-rejected Declines path', async () => {
    // Full success — every fork fulfilled → Accept.
    const clean = await forkRaceFold({
      forks: [async () => 1, async () => 2] as ForkTask<number>[],
      fold: sum,
    });
    expect(clean.verdict).toBe(Verdict.Accept);
    expect(isAccept(clean.verdict)).toBe(true);

    // Partial — one fork rejects but a survivor remains. The old boolean
    // (`sawRejection`) could only say "rejection seen" and squashed this
    // into the reject bucket; the verdict DEFERS instead (recoverable).
    const partial = await forkRaceFold({
      forks: [
        async () => 7,
        async () => {
          throw new Error('budget exhausted');
        },
      ] as ForkTask<number>[],
      fold: sum,
    });
    expect(partial.output).toBe(7); // fold still produced an output
    expect(partial.report.rejectedCount).toBe(1);
    expect(partial.report.survivorCount).toBe(1);
    expect(partial.verdict).toBe(Verdict.Abstain);
    expect(isDefer(partial.verdict)).toBe(true);
    // The defer is NOT a reject — the thing the bool could not express.
    expect(isReject(partial.verdict)).toBe(false);
  });

  it('forkFold shorthand matches forkRaceFold output', async () => {
    const forks: ForkTask<number>[] = [
      async () => 4,
      async () => 5,
      async () => 6,
    ];
    const short = await forkFold(forks, sum);
    const long = await forkRaceFold({ forks, fold: sum });
    expect(short).toBe(long.output);
    expect(short).toBe(15);
  });
});
